  ('Round-Off Rebound / Snap-Down to Stick', 'round-off-rebound-snap-down-to-stick', 'Output-phase drill: Round-Off Rebound / Snap-Down to Stick. Express force quickly with high intent and full recovery.', 'INTERMEDIATE', 8, 4, 1, NULL, 60, 25, 'Round-Off Rebound — high-intent Output expression while fresh.', 'Use in Output (reactive agility tumbling output) while the athlete is fresh. Stop when speed or quality drops.', 'Move fast with intent; full reset between reps; quality beats volume.', 'Reactive agility & tumbling output', 'reactive_agility_tumbling_output', 'tumbling_rebound_output', '{"primary_joint_actions":["multi_joint"],"primary_tissues":[],"breathing_demand":"nasal","balance_demand":"stable","impact_level":3}'::jsonb, '{"movement_description":"Output-phase drill: Round-Off Rebound / Snap-Down to Stick. Express force quickly with high intent and full recovery.","setup":["Clear sprint lane or mat space","Confirm athlete is fresh and pain-free"],"execution_steps":["Set up with crisp posture and intent","Execute one high-quality rep","Reset fully before the next rep"],"coach_cues":["Fast and sharp","Stick the landing or finish","Quality over volume"],"common_faults":["Speed drops","Sloppy mechanics","Short rest between reps"]}'::jsonb)
