INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary, what_it_is, why_it_matters,
  why_it_goes_here, programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name,
  e.card_summary,
  COALESCE(e.description, e.name),
  'Trains fast, explosive force expression while the athlete is fresh enough to attack each rep.',
  CASE e.phase_subrole
    WHEN 'acceleration_start_speed' THEN 'Belongs in Acceleration & Start Speed — expresses first-step projection and horizontal drive while fresh.'
    WHEN 'max_velocity_exposure' THEN 'Belongs in Max-Velocity Exposure — controlled upright speed with full recovery between reps.'
    WHEN 'elastic_stiffness_plyometric_rudiments' THEN 'Belongs in Elastic Stiffness / Plyometric Rudiments — short contacts and landing-to-rebound stiffness.'
    WHEN 'jump_throw_explosive_power' THEN 'Belongs in Jump, Throw & Explosive Power — max-intent jumps and throws with clean landings.'
    WHEN 'deceleration_cod_power' THEN 'Belongs in Deceleration / COD Power — crisp braking and redirection at low volume.'
    WHEN 'reactive_agility_tumbling_output' THEN 'Belongs in Reactive Agility & Tumbling Output — cue-driven bursts and tumbling expression with prerequisites.'
    ELSE 'Place in Output while fresh — after Prepare and Skill, before Capacity and Fitness.'
  END,
  'Low volume, high intent, full recovery. Stop when speed, height, landing, or reaction quality drops.',
  'Do not use as conditioning with short rest or high rep burnout.',
  'Reduce reps/contacts and extend rest for youth and beginners.'
FROM coaching.exercise e
WHERE e.slug IN ('falling-start-to-5-10-yard-sprint', 'two-point-start-to-5-10-yard-sprint', 'three-point-start-acceleration', 'half-kneeling-start-sprint', 'push-up-prone-start-sprint', 'lateral-start-to-sprint-breakout', 'backpedal-to-sprint-turn', 'partner-chase-acceleration', 'light-sled-sprint-band-resisted-acceleration', 'low-incline-hill-sprint-acceleration', 'build-up-sprint-stride-out', 'flying-10', 'flying-20', 'sprint-float-sprint', 'ins-and-outs', 'wicket-runs', 'mini-hurdle-sprint-rhythm', 'curved-sprint-arc-run', 'fast-low-pogos', 'forward-backward-pogos', 'lateral-line-hops', 'single-leg-pogo-hold-to-hop', 'snap-down-to-stick', 'snap-down-to-rebound', 'drop-landing-to-stick', 'depth-drop-to-rebound', 'hurdle-hop-series-low-hurdles', 'countermovement-vertical-jump', 'squat-jump', 'broad-jump-to-stick', 'single-broad-jump-to-rebound', 'lateral-bound-to-stick', 'skater-bound-continuous', 'split-jump-scissor-jump', 'medicine-ball-chest-pass', 'medicine-ball-overhead-slam', 'medicine-ball-rotational-scoop-toss', 'medicine-ball-shot-put-throw', 'sprint-to-stick-deceleration', '5-yard-accel-to-decel-stick', 'lateral-bound-to-decel-stick', 'pro-agility-5-10-5-technical-rep', '90-degree-cut-drill', '180-degree-turn-shuttle-cut', 'curved-run-to-cut', 'reactive-gate-sprint', 'mirror-shuffle-to-sprint-exit', 'ball-drop-sprint-catch', 'power-hurdle-to-cartwheel-round-off-entry', 'round-off-rebound-snap-down-to-stick')
